"""
OpenRouter API client with retry logic and rate limiting.
"""

import time
import sys
import os
import logging

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
from src.config import (
    OPENROUTER_API_KEY,
    OPENROUTER_BASE_URL,
    MAX_TOKENS,
    TEMPERATURE,
    REQUEST_DELAY_SECONDS,
    MAX_RETRIES,
)

try:
    from openai import OpenAI
except ImportError:
    raise ImportError("openai package required: uv pip install openai")

logger = logging.getLogger(__name__)


def build_client() -> OpenAI:
    return OpenAI(
        api_key=OPENROUTER_API_KEY,
        base_url=OPENROUTER_BASE_URL,
    )


def query_model(
    client: OpenAI,
    model_id: str,
    user_message: str,
    system_prompt: str | None = None,
    max_tokens: int = MAX_TOKENS,
    temperature: float = TEMPERATURE,
) -> dict:
    """Query a model via OpenRouter and return response dict with metadata."""
    messages = []
    if system_prompt:
        messages.append({"role": "system", "content": system_prompt})
    messages.append({"role": "user", "content": user_message})

    for attempt in range(MAX_RETRIES):
        try:
            response = client.chat.completions.create(
                model=model_id,
                messages=messages,
                max_tokens=max_tokens,
                temperature=temperature,
            )
            content = response.choices[0].message.content or ""
            return {
                "success": True,
                "content": content,
                "model": model_id,
                "usage": {
                    "prompt_tokens": response.usage.prompt_tokens if response.usage else 0,
                    "completion_tokens": response.usage.completion_tokens if response.usage else 0,
                },
                "finish_reason": response.choices[0].finish_reason,
            }
        except Exception as e:
            logger.warning(f"API call attempt {attempt + 1}/{MAX_RETRIES} failed: {e}")
            if attempt < MAX_RETRIES - 1:
                wait = 2 ** attempt * 2  # Exponential backoff: 2, 4 seconds
                logger.info(f"Retrying in {wait}s...")
                time.sleep(wait)
            else:
                logger.error(f"All {MAX_RETRIES} attempts failed for model {model_id}")
                return {
                    "success": False,
                    "content": "",
                    "model": model_id,
                    "error": str(e),
                }
        finally:
            time.sleep(REQUEST_DELAY_SECONDS)

    return {"success": False, "content": "", "model": model_id, "error": "max_retries_exceeded"}


if __name__ == "__main__":
    client = build_client()
    result = query_model(client, "mistralai/mistral-7b-instruct", "Say hello in one sentence.")
    print("Test response:", result["content"][:100])

