        messages.append({"role": "system", "content": system_prompt})
    messages.append({"role": "user", "content": user_message})

    for attempt in range(MAX_RETRIES):
        try:
            response = client.chat.completions.create(
                model=model_id,
                messages=messages,
                max_tokens=max_tokens,
                temperature=temperature,
            )
            content = response.choices[0].message.content or ""
            return {
                "success": True,
                "content": content,
                "model": model_id,
                "usage": {
                    "prompt_tokens": response.usage.prompt_tokens if response.usage else 0,
                    "completion_tokens": response.usage.completion_tokens if response.usage else 0,
                },
                "finish_reason": response.choices[0].finish_reason,
            }
        except Exception as e:
            err_str = str(e)
            # 403 errors are permanent (content moderation) — don't retry
            if "403" in err_str and ("illicit" in err_str or "Forbidden" in err_str or "moderation" in err_str):
                logger.warning(f"  403 moderation block for {model_id} — treating as refusal (no retry)")
                return {
                    "success": True,  # Treat as a valid response (model/infra refused)
                    "content": "I cannot help with this request as it violates content policies.",
                    "model": model_id,
                    "moderated": True,
                }
            logger.warning(f"API call attempt {attempt + 1}/{MAX_RETRIES} failed: {err_str[:120]}")
            if attempt < MAX_RETRIES - 1:
                wait = 2  # Fixed 2-second backoff (not exponential)
                logger.info(f"Retrying in {wait}s...")
                time.sleep(wait)
            else:
                logger.error(f"All {MAX_RETRIES} attempts failed for model {model_id}")
                return {
                    "success": False,
                    "content": "",
                    "model": model_id,
                    "error": err_str,
                }
        finally:
            time.sleep(REQUEST_DELAY_SECONDS)

    return {"success": False, "content": "", "model": model_id, "error": "max_retries_exceeded"}


if __name__ == "__main__":
